const PB_URL=($('Config').first().json.pbUrl||'').replace(/\/+$/,'');
const token=$('PB Auth').first().json.token; const pbH={Authorization:token};
const GET=(coll,qs)=>this.helpers.httpRequest({method:'GET',url:PB_URL+'/api/collections/'+coll+'/records',qs,headers:pbH,json:true});
const PATCH=(coll,id,b)=>this.helpers.httpRequest({method:'PATCH',url:PB_URL+'/api/collections/'+coll+'/records/'+id,headers:pbH,body:b,json:true});
// 1) control flag (Pause)
const sres=await GET('settings',{filter:"key='search_discover'",perPage:1});
const cfg=((sres.items&&sres.items[0])||{}).value||{};
if(cfg.enabled!==true) return [{json:{paused:true}}];
const cap=Number(cfg.batch_size||5); const staleMs=Number(cfg.stale_minutes||10)*60000; const now=Date.now();
// 2) reconcile in-flight ('searching'): the processor flips rows to 'searched'/'error' itself.
// Anything still 'searching' past the stale window lost its callback -> retry (or give up).
const proc=await GET('search_keywords',{filter:"status='searching'",perPage:200});
let inflight=0, reset=0, errored=0;
for(const row of (proc.items||[])){
  const upd=row.updated?Date.parse(row.updated):0;
  if(upd && (now-upd)>staleMs){ if((row.attempts||0)>=3){ try{await PATCH('search_keywords',row.id,{status:'error',notes:'stale (no callback after retries)'});}catch(_){}; errored++; } else { try{await PATCH('search_keywords',row.id,{status:'pending'});}catch(_){}; reset++; } continue; }
  inflight++;
}
// 3) backpressure: top up to cap with pending keywords, dispatch one processor each
const slots=Math.max(0,cap-inflight); let fired=0;
if(slots>0){
  const q=await GET('search_keywords',{filter:"status='pending'",sort:'created',perPage:slots});
  for(const row of (q.items||[])){
    try{ await PATCH('search_keywords',row.id,{status:'searching',attempts:(row.attempts||0)+1}); }catch(e){ continue; }
    const path=(row.target==='tournaments')?'tournament-process':'search-keyword-process';
    try{ await this.helpers.httpRequest({method:'POST',url:'https://n8n-2.biceps.digital/webhook/'+path,headers:{'Content-Type':'application/json'},body:{id:row.id},json:true,timeout:15000}); }catch(e){}
    fired++;
  }
}
return [{json:{inflight,slots,fired,reset,errored}}];
